#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=505;
const ll inf=1e17;
ll n,p,q,s,t,fir[N],lev[N];
struct node
{
	ll v,w,fan;
};
vector<node> g[N];
void add(int u,int v,ll w)
{
//	cout<<u<<" "<<v<<" "<<w<<"\n";
	g[u].push_back({v,w,g[v].size()});
	g[v].push_back({u,0,g[u].size()-1});
}
bool bfs()
{
	for(int i=1;i<=N-5;i++)
	{
		lev[i]=inf;
	}
	memset(fir,0,sizeof(fir));
	queue<int> q;
	q.push(s);
	lev[s]=0;
	while(!q.empty())
	{
		int u=q.front();
		q.pop();
		for(int i=0;i<g[u].size();i++)
		{
			ll v=g[u][i].v,w=g[u][i].w;
			if((w>0)&&(lev[v]==inf))
			{
				q.push(v);
				lev[v]=lev[u]+1;
				if(v==t) return 1;
			}
		}
	}
	return 0;
}
ll dfs(int u,ll num)
{
//	cout<<"aa"<<u<<" "<<num<<"\n";
	if(u==t) return num;
	ll ans=0;
	for(int i=fir[u];i<g[u].size();i++)
	{
		fir[u]=i;
		ll v=g[u][i].v,w=g[u][i].w;
		if(w==0) continue;
		if(lev[v]!=lev[u]+1) continue;
		ll lstnum=dfs(v,min(num,w));
		g[u][i].w-=lstnum;
		g[v][g[u][i].fan].w+=lstnum;
		num-=lstnum;
		ans+=lstnum;
	}
	return ans;
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>p>>q;
	// 1~p 房间
	// p+1~p+q 菜
	// p+q+1~p+q+2*n 人（人_1 和 人_2）
	// s:p+q+2*n+1 t:p+q+2*n+2
	s=p+q+2*n+1;
	t=s+1;
	for(int i=1;i<=p;i++) 
	{
		add(s,i,1);
	}
	for(int i=p+1;i<=q+p;i++)
	{
		add(i,t,1);
	}
	for(int i=p+q+1;i<=p+q+n;i++)
	{
		add(i,i+n,1);
	}
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=p;j++)
		{
			int x;
			cin>>x;
			if(x==1)
			{
				add(j,p+q+i,1);
			}
		}
	}
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=q;j++)
		{
			int x;
			cin>>x;
			if(x==1)
			{
				add(p+q+i+n,p+j,1);
			}
		}
	}
	ll ans=0;
	while(bfs())
	{
		ans+=dfs(s,inf);
	}
	cout<<ans;
	return 0;
}
